# fetch all csv files
def get_csv_files():
    try:
        files = mssparkutils.fs.ls(csv_base_path)

        csv_files = [
            {
                "table_name": f.name.replace(".csv", ""),
                "csv_path": f.name,
                "full_path": f.path
            }
            for f in files
            if f.name.endswith(".csv") and not f.name.startswith("_")
        ]

        print(f" Found {len(csv_files)} csv files")
        return csv_files

    except Exception as e:
        print(f"failed to get csv files: {str(e)}")
        return []

csv_files = discover_csv_files()

if not csv_files:
    raise Exception("No csv files were found to clean")
